package pe.org.camaracomercioica.protestos.util; import pe.org.camaracomercioica.protestos.model.EstadoSolicitud; import java.util.*; public final class SolicitudStatePolicy { private SolicitudStatePolicy(){} private static final Map<EstadoSolicitud,Set<EstadoSolicitud>> ALLOWED=Map.of(EstadoSolicitud.REGISTRADA,Set.of(EstadoSolicitud.EN_REVISION,EstadoSolicitud.RECHAZADA),EstadoSolicitud.EN_REVISION,Set.of(EstadoSolicitud.OBSERVADA,EstadoSolicitud.APROBADA,EstadoSolicitud.RECHAZADA),EstadoSolicitud.OBSERVADA,Set.of(EstadoSolicitud.EN_REVISION,EstadoSolicitud.RECHAZADA),EstadoSolicitud.APROBADA,Set.of(),EstadoSolicitud.RECHAZADA,Set.of()); public static boolean canTransition(EstadoSolicitud from,EstadoSolicitud to){return from==to||ALLOWED.getOrDefault(from,Set.of()).contains(to);} }
